		})
		assert.NoError(t, err)
		assert.NotNil(t, agent)

		// Initialize a run context to enable session storage
		input := &AgentInput{
			Messages: []Message{
				schema.UserMessage("Hello, who are you?"),
			},
		}
		ctx, runCtx := initRunCtx(ctx, "TestAgent", input)
