func TestNesting(t *testing.T) {
	ctx := context.Background()
	cb := &myCallback{t: t}
	ctx = InitCallbacks(ctx, &RunInfo{
		Name: "test",
	}, cb)

	// jumped
	ctx1 := OnStart(ctx, 0)
	ctx2 := OnStart(ctx1, 1)
	OnEnd(ctx2, 1)
	OnEnd(ctx1, 0)
	assert.Equal(t, 4, cb.times)

	// reused
	cb.times = 0
	ctx1 = OnStart(ctx, 0)
	ctx2 = ReuseHandlers(ctx1, &RunInfo{Name: "test2"})
	ctx3 := OnStart(ctx2, 1)
	OnEnd(ctx3, 1)
	OnEnd(ctx1, 0)
	assert.Equal(t, 4, cb.times)

}

