components.prompt.chat_template.DefaultC.source_code:
func (t *DefaultChatTemplate) Format(ctx context.Context,
	vs map[string]any, _ ...Option) (result []*schema.Message, err error) {
	ctx = callbacks.EnsureRunInfo(ctx, t.GetType(), components.ComponentOfPrompt)
	ctx = callbacks.OnStart(ctx, &CallbackInput{
		Variables: vs,
		Templates: t.templates,
	})
	defer func() {
		if err != nil {
			_ = callbacks.OnError(ctx, err)
		}
	}()

	result = make([]*schema.Message, 0, len(t.templates))
	for _, template := range t.templates {
		msgs, err := template.Format(ctx, vs, t.formatType)
		if err != nil {
			return nil, err
		}

		result = append(result, msgs...)
	}

	_ = callbacks.OnEnd(ctx, &CallbackOutput{
		Result:    result,
		Templates: t.templates,
	})

	return result, nil
}

components.prompt.chat_template_test.Tes.source_code:
func TestFormat(t *testing.T) {
	pyFmtTestTemplate := []schema.MessagesTemplate{
		schema.SystemMessage(
			"you are a helpful assistant.\n" +
				"here is the context: {context}"),
		schema.MessagesPlaceholder("chat_history", true),
		schema.UserMessage("question: {question}"),
	}
	jinja2TestTemplate := []schema.MessagesTemplate{
		schema.SystemMessage(
			"you are a helpful assistant.\n" +
				"here is the context: {{context}}"),
		schema.MessagesPlaceholder("chat_history", true),
		schema.UserMessage("question: {{question}}"),
	}
	goFmtTestTemplate := []schema.MessagesTemplate{
		schema.SystemMessage(
			"you are a helpful assistant.\n" +
				"here is the context: {{.context}}"),
		schema.MessagesPlaceholder("chat_history", true),
		schema.UserMessage("question: {{.question}}"),
	}
	testValues := map[string]any{
		"context":  "it's beautiful day",
		"question": "how is the day today",
		"chat_history": []*schema.Message{
			schema.UserMessage("who are you"),
			schema.AssistantMessage("I'm a helpful assistant", nil),
		},
	}
	expected := []*schema.Message{
		schema.SystemMessage(
			"you are a helpful assistant.\n" +
				"here is the context: it's beautiful day"),
		schema.UserMessage("who are you"),
		schema.AssistantMessage("I'm a helpful assistant", nil),
		schema.UserMessage("question: how is the day today"),
	}

	// FString
	chatTemplate := FromMessages(schema.FString, pyFmtTestTemplate...)
	msgs, err := chatTemplate.Format(context.Background(), testValues)
	assert.Nil(t, err)
	assert.Equal(t, expected, msgs)

	// Jinja2
	chatTemplate = FromMessages(schema.Jinja2, jinja2TestTemplate...)
	msgs, err = chatTemplate.Format(context.Background(), testValues)
	assert.Nil(t, err)
	assert.Equal(t, expected, msgs)

	// GoTemplate
	chatTemplate = FromMessages(schema.GoTemplate, goFmtTestTemplate...)
	msgs, err = chatTemplate.Format(context.Background(), testValues)
	assert.Nil(t, err)
	assert.Equal(t, expected, msgs)
}

func TestDocumentFormat(t *testing.T) {
	docs := []*schema.Document{
		{
			ID:      "1",
			Content: "qwe",
			MetaData: map[string]any{
				"hello": 888,
			},
		},
		{
			ID:      "2",
			Content: "asd",
			MetaData: map[string]any{
				"bye": 111,
			},
		},
	}

	template := FromMessages(schema.FString,
		schema.SystemMessage("all:{all_docs}\nsingle:{single_doc}"),
	)

	msgs, err := template.Format(context.Background(), map[string]any{
		"all_docs":   docs,
		"single_doc": docs[0],
	})

	assert.Nil(t, err)
	t.Log(msgs)
}

func TestMultiContentFormat(t *testing.T) {
	mtpl := []schema.MessagesTemplate{
		&schema.Message{
			Content: "{a}",
			MultiContent: []schema.ChatMessagePart{
				{
					Type: schema.ChatMessagePartTypeText,
					Text: "{b}",
				},
				{
					Type: schema.ChatMessagePartTypeImageURL,
					ImageURL: &schema.ChatMessageImageURL{
						URL: "{c}",
					},
				},
				{
					Type: schema.ChatMessagePartTypeAudioURL,
					AudioURL: &schema.ChatMessageAudioURL{
						URL: "{d}",
					},
				},
				{
					Type: schema.ChatMessagePartTypeVideoURL,
					VideoURL: &schema.ChatMessageVideoURL{
						URL: "{e}",
					},
				},
				{
					Type: schema.ChatMessagePartTypeFileURL,
					FileURL: &schema.ChatMessageFileURL{
						URL: "{f}",
					},
				},
			},
		},
	}
	input := map[string]any{
		"a": "content",
		"b": "text",
		"c": "image url",
		"d": "audio url",
		"e": "video url",
		"f": "file url",
	}
	expected := []*schema.Message{
		{
			Content: "content",
			MultiContent: []schema.ChatMessagePart{
				{
					Type: schema.ChatMessagePartTypeText,
					Text: "text",
				},
				{
					Type: schema.ChatMessagePartTypeImageURL,
					ImageURL: &schema.ChatMessageImageURL{
						URL: "image url",
					},
				},
				{
					Type: schema.ChatMessagePartTypeAudioURL,
					AudioURL: &schema.ChatMessageAudioURL{
						URL: "audio url",
					},
				},
				{
					Type: schema.ChatMessagePartTypeVideoURL,
					VideoURL: &schema.ChatMessageVideoURL{
						URL: "video url",
					},
				},
				{
					Type: schema.ChatMessagePartTypeFileURL,
					FileURL: &schema.ChatMessageFileURL{
						URL: "file url",
					},
				},
			},
		},
	}

	tpl := FromMessages(schema.FString, mtpl...)
	result, err := tpl.Format(context.Background(), input)
	assert.Nil(t, err)
	assert.Equal(t, expected, result)
}

