compose.graph.uniqueSlice.source_code:
func uniqueSlice(s []string) []string {
	seen := make(map[string]struct{}, len(s))
	cur := 0
	for i := range s {
		if _, ok := seen[s[i]]; !ok {
			seen[s[i]] = struct{}{}
			s[cur] = s[i]
			cur++
		}
	}
	return s[:cur]
}

