							ID: randStr(),
							Function: schema.FunctionCall{
								Name:      streamInfo.Name,
								Arguments: fmt.Sprintf(`{"name": "%s", "hh": "stream tool"}`, randStr()),
							},
						},
					}),
					nil)
				return sr, nil
			} else if times == 4 { // parallel tool call
				sw.Send(schema.AssistantMessage("hello max",
					[]schema.ToolCall{
						{
							ID: randStr(),
							Function: schema.FunctionCall{
								Name:      info.Name,
