internal.core.address.Address.String.source_code:
func (p Address) String() string {
	if p == nil {
		return ""
	}
	var sb strings.Builder
	for i, s := range p {
		sb.WriteString(string(s.Type))
		sb.WriteString(":")
		sb.WriteString(s.ID)
		if s.SubID != "" {
			sb.WriteString(":")
			sb.WriteString(s.SubID)
		}
		if i != len(p)-1 {
			sb.WriteString(";")
		}
	}
	return sb.String()
}

internal.core.address.Address.Equals.source_code:
func (p Address) Equals(other Address) bool {
	if len(p) != len(other) {
		return false
	}
	for i := range p {
		if p[i].Type != other[i].Type || p[i].ID != other[i].ID || p[i].SubID != other[i].SubID {
			return false
		}
	}
	return true
}

