			Address: Address{{Type: AddressSegmentAgent, ID: "agent1"}},
			Parent:  parent1,
		}
		ctx2 := &InterruptCtx{
			Address: Address{{Type: AddressSegmentAgent, ID: "agent1"}},
			Parent:  parent2,
		}

		assert.False(t, ctx1.EqualsWithoutID(ctx2))
