func TestParseTypeName(t *testing.T) {
	t.Run("named_struct", func(t *testing.T) {
		type OpenAI struct{}
		model := &OpenAI{}
		name := ParseTypeName(reflect.Indirect(reflect.ValueOf(model)))
		assert.Equal(t, "OpenAI", name)
