internal.gmap.gmap.Concat.source_code:
func Concat[K comparable, V any](ms ...map[K]V) map[K]V {
	// FastPath: no map or only one map given.
	if len(ms) == 0 {
		return make(map[K]V)
	}
	if len(ms) == 1 {
		return cloneWithoutNilCheck(ms[0])
	}

	var maxLen int
	for _, m := range ms {
		if len(m) > maxLen {
			maxLen = len(m)
		}
	}
	ret := make(map[K]V, maxLen)
	// FastPath: all maps are empty.
	if maxLen == 0 {
		return ret
	}

	// Concat all maps.
	for _, m := range ms {
		for k, v := range m {
			ret[k] = v
		}
	}
	return ret
}

