			ts[0] = time.Now().UnixMilli()
			interval := ts[0] - tsOld[0]
			if interval >= 6 {
				atomic.AddInt32(&count, 1)
			}
			assert.Equal(t, i, n)
			i++
		}
		wg.Done()
	}()
	go func() {
